using TMPro; using UnityEngine; using NabyeolDabyeolDreamPuzzle.Stage;
namespace NabyeolDabyeolDreamPuzzle.UI { public class ScoreTextUI:MonoBehaviour{ [SerializeField] ScoreManager scoreManager; [SerializeField] TMP_Text scoreText; [SerializeField] string prefix="Score: "; void Awake(){ scoreManager??=FindAnyObjectByType<ScoreManager>(); scoreText??=GetComponent<TMP_Text>(); } void OnEnable(){ if(scoreManager!=null) scoreManager.OnScoreChanged+=UpdateText; } void OnDisable(){ if(scoreManager!=null) scoreManager.OnScoreChanged-=UpdateText; } void Start()=>Refresh(); public void Refresh()=>UpdateText(scoreManager?scoreManager.CurrentScore:0); void UpdateText(int score){ if(scoreText!=null) scoreText.text=$"{prefix}{score}"; }} }
